def _sap_erp_function_module_to_nested(
    sap_erp_function_module: SapErpFunctionModule,
) -> SapErpFunctionModuleNested:
    """Convert flat SapErpFunctionModule to nested format."""
    attrs = SapErpFunctionModuleAttributes()
    _populate_sap_erp_function_module_attrs(attrs, sap_erp_function_module)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        sap_erp_function_module,
        _SAP_ERP_FUNCTION_MODULE_REL_FIELDS,
        SapErpFunctionModuleRelationshipAttributes,
    )
    return SapErpFunctionModuleNested(
        guid=sap_erp_function_module.guid,
        type_name=sap_erp_function_module.type_name,
        status=sap_erp_function_module.status,
        version=sap_erp_function_module.version,
        create_time=sap_erp_function_module.create_time,
        update_time=sap_erp_function_module.update_time,
        created_by=sap_erp_function_module.created_by,
        updated_by=sap_erp_function_module.updated_by,
        classifications=sap_erp_function_module.classifications,
        classification_names=sap_erp_function_module.classification_names,
        meanings=sap_erp_function_module.meanings,
        labels=sap_erp_function_module.labels,
        business_attributes=sap_erp_function_module.business_attributes,
        custom_attributes=sap_erp_function_module.custom_attributes,
        pending_tasks=sap_erp_function_module.pending_tasks,
        proxy=sap_erp_function_module.proxy,
        is_incomplete=sap_erp_function_module.is_incomplete,
        provenance_type=sap_erp_function_module.provenance_type,
        home_id=sap_erp_function_module.home_id,
        depth=sap_erp_function_module.depth,
        immediate_upstream=sap_erp_function_module.immediate_upstream,
        immediate_downstream=sap_erp_function_module.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _sap_erp_function_module_from_nested(
    nested: SapErpFunctionModuleNested,
) -> SapErpFunctionModule:
    """Convert nested format to flat SapErpFunctionModule."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SapErpFunctionModuleAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SAP_ERP_FUNCTION_MODULE_REL_FIELDS,
        SapErpFunctionModuleRelationshipAttributes,
    )
    return SapErpFunctionModule(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_sap_erp_function_module_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _sap_erp_function_module_to_nested_bytes(
    sap_erp_function_module: SapErpFunctionModule, serde: Serde
) -> bytes:
    """Convert flat SapErpFunctionModule to nested JSON bytes."""
    return serde.encode(_sap_erp_function_module_to_nested(sap_erp_function_module))


def _sap_erp_function_module_from_nested_bytes(
    data: bytes, serde: Serde
) -> SapErpFunctionModule:
    """Convert nested JSON bytes to flat SapErpFunctionModule."""
    nested = serde.decode(data, SapErpFunctionModuleNested)
    return _sap_erp_function_module_from_nested(nested)


